import{_ as o,c as s,o as e,a1 as a}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"AI-агенты: Обзор 10 экспертов | oh-my-opencode","description":"Изучите 10 AI-агентов oh-my-opencode. Выбирайте агентов по типу задачи для эффективной совместной работы и параллельного выполнения.","frontmatter":{"title":"AI-агенты: Обзор 10 экспертов | oh-my-opencode","sidebarTitle":"Знакомство с 10 AI-экспертами","subtitle":"AI-агенты: Обзор 10 экспертов","description":"Изучите 10 AI-агентов oh-my-opencode. Выбирайте агентов по типу задачи для эффективной совместной работы и параллельного выполнения.","tags":["ai-agents","orchestration"],"prerequisite":["start-sisyphus-orchestrator"],"order":60},"headers":[],"relativePath":"ru/code-yeongyu/oh-my-opencode/advanced/ai-agents-overview/index.md","filePath":"ru/code-yeongyu/oh-my-opencode/advanced/ai-agents-overview/index.md"}'),n={name:"ru/code-yeongyu/oh-my-opencode/advanced/ai-agents-overview/index.md"};function r(l,t,i,d,p,g){return e(),s("div",null,[...t[0]||(t[0]=[a(`<h1 id="команда-ai-агентов-обзор-10-экспертов" tabindex="-1">Команда AI-агентов: Обзор 10 экспертов <a class="header-anchor" href="#команда-ai-агентов-обзор-10-экспертов" aria-label="Permalink to &quot;Команда AI-агентов: Обзор 10 экспертов&quot;">​</a></h1><h2 id="что-вы-сможете-делать-после-изучения" tabindex="-1">Что вы сможете делать после изучения <a class="header-anchor" href="#что-вы-сможете-делать-после-изучения" aria-label="Permalink to &quot;Что вы сможете делать после изучения&quot;">​</a></h2><ul><li>Понимать обязанности и специализацию 10 встроенных AI-агентов</li><li>Быстро выбирать наиболее подходящего агента по типу задачи</li><li>Понимать механизмы взаимодействия между агентами (делегирование, параллелизм, проверка)</li><li>Освоить ограничения прав доступа и сценарии использования различных агентов</li></ul><h2 id="основная-идея-сотрудничество-как-в-реальнои-команде" tabindex="-1">Основная идея: Сотрудничество как в реальной команде <a class="header-anchor" href="#основная-идея-сотрудничество-как-в-реальнои-команде" aria-label="Permalink to &quot;Основная идея: Сотрудничество как в реальной команде&quot;">​</a></h2><p><strong>Основная концепция oh-my-opencode</strong>: <strong>Не рассматривайте AI как универсального помощника, а как профессиональную команду</strong>.</p><p>В реальной команде разработки вам нужны:</p><ul><li><strong>Главный оркестратор</strong> (Tech Lead): планирование, распределение задач, отслеживание прогресса</li><li><strong>Архитектурный консультант</strong> (Architect): технические решения и рекомендации по архитектуре</li><li><strong>Код-ревьюер</strong> (Reviewer): проверка качества кода, выявление потенциальных проблем</li><li><strong>Исследовательский эксперт</strong> (Researcher): поиск документации, исследование open source решений, изучение лучших практик</li><li><strong>Код-детектив</strong> (Searcher): быстрый поиск кода, поиск ссылок, понимание существующих реализаций</li><li><strong>Frontend-дизайнер</strong> (Frontend Designer): проектирование UI, настройка стилей</li><li><strong>Git-эксперт</strong> (Git Master): коммиты кода, управление ветками, поиск в истории</li></ul><p>oh-my-opencode превратил эти роли в 10 профессиональных AI-агентов, которые вы можете гибко комбинировать в зависимости от типа задачи.</p><h2 id="подробное-описание-10-агентов" tabindex="-1">Подробное описание 10 агентов <a class="header-anchor" href="#подробное-описание-10-агентов" aria-label="Permalink to &quot;Подробное описание 10 агентов&quot;">​</a></h2><h3 id="главные-оркестраторы-2-агента" tabindex="-1">Главные оркестраторы (2 агента) <a class="header-anchor" href="#главные-оркестраторы-2-агента" aria-label="Permalink to &quot;Главные оркестраторы (2 агента)&quot;">​</a></h3><h4 id="sisyphus-главныи-оркестратор" tabindex="-1">Sisyphus - Главный оркестратор <a class="header-anchor" href="#sisyphus-главныи-оркестратор" aria-label="Permalink to &quot;Sisyphus - Главный оркестратор&quot;">​</a></h4><p><strong>Роль</strong>: Главный оркестратор, ваш основной технический руководитель</p><p><strong>Возможности</strong>:</p><ul><li>Глубокое рассуждение (32k thinking budget)</li><li>Планирование и делегирование сложных задач</li><li>Выполнение модификации и рефакторинга кода</li><li>Управление всем процессом разработки</li></ul><p><strong>Рекомендуемая модель</strong>: <code>anthropic/claude-opus-4-5</code> (temperature: 0.1)</p><p><strong>Сценарии использования</strong>:</p><ul><li>Повседневные задачи разработки (новые функции, исправление багов)</li><li>Сложные проблемы, требующие глубокого рассуждения</li><li>Декомпозиция и выполнение многошаговых задач</li><li>Сценарии, требующие параллельного делегирования другим агентам</li></ul><p><strong>Способ вызова</strong>:</p><ul><li>Агент по умолчанию (выбор &quot;Sisyphus&quot; в селекторе OpenCode Agent)</li><li>Прямой ввод задачи в промпте, без специальных триггерных слов</li></ul><p><strong>Права доступа</strong>: Полные права на инструменты (write, edit, bash, delegate_task и др.)</p><hr><h4 id="atlas-менеджер-todo" tabindex="-1">Atlas - Менеджер TODO <a class="header-anchor" href="#atlas-менеджер-todo" aria-label="Permalink to &quot;Atlas - Менеджер TODO&quot;">​</a></h4><p><strong>Роль</strong>: Главный оркестратор, специализируется на управлении TODO-списками и отслеживании выполнения задач</p><p><strong>Возможности</strong>:</p><ul><li>Управление и отслеживание TODO-списков</li><li>Систематизированное выполнение планов</li><li>Мониторинг прогресса задач</li></ul><p><strong>Рекомендуемая модель</strong>: <code>anthropic/claude-opus-4-5</code> (temperature: 0.1)</p><p><strong>Сценарии использования</strong>:</p><ul><li>Запуск выполнения проекта командой <code>/start-work</code></li><li>Необходимость строгого следования плану для завершения задач</li><li>Систематизированное отслеживание прогресса задач</li></ul><p><strong>Способ вызова</strong>:</p><ul><li>Использование слэш-команды <code>/start-work</code></li><li>Автоматическая активация через Atlas Hook</li></ul><p><strong>Права доступа</strong>: Полные права на инструменты</p><hr><h3 id="консультанты-и-проверка-3-агента" tabindex="-1">Консультанты и проверка (3 агента) <a class="header-anchor" href="#консультанты-и-проверка-3-агента" aria-label="Permalink to &quot;Консультанты и проверка (3 агента)&quot;">​</a></h3><h4 id="oracle-стратегическии-консультант" tabindex="-1">Oracle - Стратегический консультант <a class="header-anchor" href="#oracle-стратегическии-консультант" aria-label="Permalink to &quot;Oracle - Стратегический консультант&quot;">​</a></h4><p><strong>Роль</strong>: Технический консультант только для чтения, эксперт по высокоинтеллектуальным рассуждениям</p><p><strong>Возможности</strong>:</p><ul><li>Рекомендации по архитектурным решениям</li><li>Диагностика сложных проблем</li><li>Код-ревью (только чтение)</li><li>Анализ компромиссов между несколькими системами</li></ul><p><strong>Рекомендуемая модель</strong>: <code>openai/gpt-5.2</code> (temperature: 0.1)</p><p><strong>Сценарии использования</strong>:</p><ul><li>Проектирование сложной архитектуры</li><li>Самопроверка после завершения важной работы</li><li>Сложная отладка после 2+ неудачных попыток исправления</li><li>Незнакомые паттерны кода или архитектура</li><li>Вопросы безопасности/производительности</li></ul><p><strong>Условия активации</strong>:</p><ul><li>Промпт содержит <code>@oracle</code> или использование <code>delegate_task(agent=&quot;oracle&quot;)</code></li><li>Автоматическая рекомендация при принятии сложных архитектурных решений</li></ul><p><strong>Ограничения</strong>: Права только на чтение (запрещены write, edit, task, delegate_task)</p><p><strong>Основные принципы</strong>:</p><ul><li><strong>Минимализм</strong>: Предпочтение самым простым решениям</li><li><strong>Использование существующих ресурсов</strong>: Приоритет модификации текущего кода, избегание новых зависимостей</li><li><strong>Приоритет опыта разработчика</strong>: Читаемость, поддерживаемость &gt; теоретическая производительность</li><li><strong>Единый четкий путь</strong>: Предоставление одной основной рекомендации, альтернативы только при значительных различиях в компромиссах</li></ul><hr><h4 id="metis-аналитик-предварительного-планирования" tabindex="-1">Metis - Аналитик предварительного планирования <a class="header-anchor" href="#metis-аналитик-предварительного-планирования" aria-label="Permalink to &quot;Metis - Аналитик предварительного планирования&quot;">​</a></h4><p><strong>Роль</strong>: Эксперт по анализу требований и оценке рисков перед планированием</p><p><strong>Возможности</strong>:</p><ul><li>Выявление скрытых требований и неявных запросов</li><li>Обнаружение неоднозначностей, которые могут привести к сбоям AI</li><li>Маркировка потенциальных паттернов AI-slop (избыточная инженерия, расползание scope)</li><li>Подготовка инструкций для агента планирования</li></ul><p><strong>Рекомендуемая модель</strong>: <code>anthropic/claude-sonnet-4-5</code> (temperature: 0.3)</p><p><strong>Сценарии использования</strong>:</p><ul><li>Перед планированием Prometheus</li><li>Когда запрос пользователя нечеткий или открытый</li><li>Предотвращение паттернов избыточной инженерии AI</li></ul><p><strong>Способ вызова</strong>: Автоматический вызов Prometheus (режим интервью)</p><p><strong>Ограничения</strong>: Права только на чтение (запрещены write, edit, task, delegate_task)</p><p><strong>Основной процесс</strong>:</p><ol><li><strong>Классификация намерения</strong>: Рефакторинг / Создание с нуля / Средняя задача / Совместная работа / Архитектура / Исследование</li><li><strong>Анализ по типу намерения</strong>: Целевые рекомендации для разных типов</li><li><strong>Генерация вопросов</strong>: Создание четких вопросов для пользователя</li><li><strong>Подготовка инструкций</strong>: Генерация четких инструкций &quot;MUST&quot; и &quot;MUST NOT&quot; для Prometheus</li></ol><hr><h4 id="momus-проверяющии-планов" tabindex="-1">Momus - Проверяющий планов <a class="header-anchor" href="#momus-проверяющии-планов" aria-label="Permalink to &quot;Momus - Проверяющий планов&quot;">​</a></h4><p><strong>Роль</strong>: Строгий эксперт по проверке планов, выявляющий все упущения и неясности</p><p><strong>Возможности</strong>:</p><ul><li>Проверка ясности, проверяемости и полноты плана</li><li>Проверка всех ссылок на файлы и контекста</li><li>Симуляция фактических шагов реализации</li><li>Выявление критических упущений</li></ul><p><strong>Рекомендуемая модель</strong>: <code>anthropic/claude-sonnet-4-5</code> (temperature: 0.1)</p><p><strong>Сценарии использования</strong>:</p><ul><li>После создания рабочего плана Prometheus</li><li>Перед выполнением сложных TODO-списков</li><li>Проверка качества плана</li></ul><p><strong>Способ вызова</strong>: Автоматический вызов Prometheus</p><p><strong>Ограничения</strong>: Права только на чтение (запрещены write, edit, task, delegate_task)</p><p><strong>Четыре критерия проверки</strong>:</p><ol><li><strong>Ясность рабочего содержания</strong>: Указан ли источник для каждой задачи?</li><li><strong>Критерии проверки и приемки</strong>: Есть ли конкретные методы проверки успеха?</li><li><strong>Полнота контекста</strong>: Предоставлен ли достаточный контекст (порог уверенности 90%)?</li><li><strong>Общее понимание</strong>: Понимает ли разработчик ПОЧЕМУ, ЧТО и КАК?</li></ol><p><strong>Основной принцип</strong>: <strong>Проверяющий документации, а не дизайн-консультант</strong>. Оценивается &quot;достаточно ли ясен план для выполнения&quot;, а не &quot;правильно ли выбран метод&quot;.</p><hr><h3 id="исследование-и-изучение-3-агента" tabindex="-1">Исследование и изучение (3 агента) <a class="header-anchor" href="#исследование-и-изучение-3-агента" aria-label="Permalink to &quot;Исследование и изучение (3 агента)&quot;">​</a></h3><h4 id="librarian-эксперт-по-исследованию-множественных-репозиториев" tabindex="-1">Librarian - Эксперт по исследованию множественных репозиториев <a class="header-anchor" href="#librarian-эксперт-по-исследованию-множественных-репозиториев" aria-label="Permalink to &quot;Librarian - Эксперт по исследованию множественных репозиториев&quot;">​</a></h4><p><strong>Роль</strong>: Эксперт по пониманию open source кодовых баз, специализируется на поиске документации и примеров реализации</p><p><strong>Возможности</strong>:</p><ul><li>GitHub CLI: клонирование репозиториев, поиск issues/PRs, просмотр истории</li><li>Context7: запрос официальной документации</li><li>Web Search: поиск последней информации</li><li>Генерация доказательств с постоянными ссылками</li></ul><p><strong>Рекомендуемая модель</strong>: <code>opencode/big-pickle</code> (temperature: 0.1)</p><p><strong>Сценарии использования</strong>:</p><ul><li>&quot;Как использовать [библиотеку]?&quot;</li><li>&quot;Каковы лучшие практики для [функции фреймворка]?&quot;</li><li>&quot;Почему [внешняя зависимость] ведет себя так?&quot;</li><li>&quot;Найти примеры использования [библиотеки]&quot;</li></ul><p><strong>Условия активации</strong>:</p><ul><li>Автоматическая активация при упоминании внешних библиотек/источников</li><li>Промпт содержит <code>@librarian</code></li></ul><p><strong>Классификация типов запросов</strong>:</p><ul><li><strong>Тип A (концептуальный)</strong>: &quot;Как сделать X?&quot;, &quot;Лучшие практики&quot;</li><li><strong>Тип B (справочная реализация)</strong>: &quot;Как X реализует Y?&quot;, &quot;Показать исходный код Z&quot;</li><li><strong>Тип C (контекст и история)</strong>: &quot;Почему это было изменено?&quot;, &quot;История X?&quot;</li><li><strong>Тип D (комплексное исследование)</strong>: Сложные/нечеткие запросы</li></ul><p><strong>Ограничения</strong>: Права только на чтение (запрещены write, edit, task, delegate_task, call_omo_agent)</p><p><strong>Обязательное требование</strong>: Все утверждения о коде должны включать постоянные ссылки на GitHub</p><hr><h4 id="explore-эксперт-по-быстрому-изучению-кодовои-базы" tabindex="-1">Explore - Эксперт по быстрому изучению кодовой базы <a class="header-anchor" href="#explore-эксперт-по-быстрому-изучению-кодовои-базы" aria-label="Permalink to &quot;Explore - Эксперт по быстрому изучению кодовой базы&quot;">​</a></h4><p><strong>Роль</strong>: Эксперт по поиску кода с учетом контекста</p><p><strong>Возможности</strong>:</p><ul><li>LSP инструменты: определения, ссылки, навигация по символам</li><li>AST-Grep: структурный поиск паттернов</li><li>Grep: текстовый поиск паттернов</li><li>Glob: сопоставление паттернов имен файлов</li><li>Параллельное выполнение (3+ инструмента одновременно)</li></ul><p><strong>Рекомендуемая модель</strong>: <code>opencode/gpt-5-nano</code> (temperature: 0.1)</p><p><strong>Сценарии использования</strong>:</p><ul><li>Широкий поиск, требующий 2+ углов поиска</li><li>Незнакомая структура модулей</li><li>Обнаружение паттернов между слоями</li><li>Поиск &quot;Где X?&quot;, &quot;Какой файл содержит Y?&quot;</li></ul><p><strong>Условия активации</strong>:</p><ul><li>Автоматическая активация при вовлечении 2+ модулей</li><li>Промпт содержит <code>@explore</code></li></ul><p><strong>Обязательный формат вывода</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;analysis&gt;</span></span>
<span class="line"><span>**Literal Request**: [буквальный запрос пользователя]</span></span>
<span class="line"><span>**Actual Need**: [что на самом деле нужно]</span></span>
<span class="line"><span>**Success Looks Like**: [как должен выглядеть успех]</span></span>
<span class="line"><span>&lt;/analysis&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;results&gt;</span></span>
<span class="line"><span>&lt;files&gt;</span></span>
<span class="line"><span>- /absolute/path/to/file1.ts — [почему этот файл релевантен]</span></span>
<span class="line"><span>- /absolute/path/to/file2.ts — [почему этот файл релевантен]</span></span>
<span class="line"><span>&lt;/files&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;answer&gt;</span></span>
<span class="line"><span>[прямой ответ на фактическую потребность]</span></span>
<span class="line"><span>&lt;/answer&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;next_steps&gt;</span></span>
<span class="line"><span>[что делать дальше]</span></span>
<span class="line"><span>&lt;/next_steps&gt;</span></span>
<span class="line"><span>&lt;/results&gt;</span></span></code></pre></div><p><strong>Ограничения</strong>: Права только на чтение (запрещены write, edit, task, delegate_task, call_omo_agent)</p><hr><h4 id="multimodal-looker-эксперт-по-анализу-медиа" tabindex="-1">Multimodal Looker - Эксперт по анализу медиа <a class="header-anchor" href="#multimodal-looker-эксперт-по-анализу-медиа" aria-label="Permalink to &quot;Multimodal Looker - Эксперт по анализу медиа&quot;">​</a></h4><p><strong>Роль</strong>: Интерпретация медиафайлов, которые невозможно прочитать как чистый текст</p><p><strong>Возможности</strong>:</p><ul><li>PDF: извлечение текста, структуры, таблиц, данных конкретных разделов</li><li>Изображения: описание макета, UI-элементов, текста, диаграмм</li><li>Диаграммы: объяснение отношений, процессов, архитектуры</li></ul><p><strong>Рекомендуемая модель</strong>: <code>google/gemini-3-flash</code> (temperature: 0.1)</p><p><strong>Сценарии использования</strong>:</p><ul><li>Необходимость извлечения структурированных данных из PDF</li><li>Описание UI-элементов или диаграмм на изображениях</li><li>Разбор диаграмм в технической документации</li></ul><p><strong>Способ вызова</strong>: Автоматическая активация через инструмент <code>look_at</code></p><p><strong>Ограничения</strong>: <strong>Белый список только для чтения</strong> (разрешен только инструмент read)</p><hr><h3 id="планирование-и-выполнение-2-агента" tabindex="-1">Планирование и выполнение (2 агента) <a class="header-anchor" href="#планирование-и-выполнение-2-агента" aria-label="Permalink to &quot;Планирование и выполнение (2 агента)&quot;">​</a></h3><h4 id="prometheus-стратегическии-планировщик" tabindex="-1">Prometheus - Стратегический планировщик <a class="header-anchor" href="#prometheus-стратегическии-планировщик" aria-label="Permalink to &quot;Prometheus - Стратегический планировщик&quot;">​</a></h4><p><strong>Роль</strong>: Эксперт по сбору требований в формате интервью и генерации рабочих планов</p><p><strong>Возможности</strong>:</p><ul><li>Режим интервью: непрерывные вопросы до полной ясности требований</li><li>Генерация рабочего плана: структурированный план в формате Markdown</li><li>Параллельное делегирование: консультация с Oracle, Metis, Momus для проверки плана</li></ul><p><strong>Рекомендуемая модель</strong>: <code>anthropic/claude-opus-4-5</code> (temperature: 0.1)</p><p><strong>Сценарии использования</strong>:</p><ul><li>Создание детального плана для сложных проектов</li><li>Проекты, требующие уточнения требований</li><li>Систематизированный рабочий процесс</li></ul><p><strong>Способ вызова</strong>:</p><ul><li>Промпт содержит <code>@prometheus</code> или &quot;использовать Prometheus&quot;</li><li>Использование слэш-команды <code>/start-work</code></li></ul><p><strong>Рабочий процесс</strong>:</p><ol><li><strong>Режим интервью</strong>: Непрерывные вопросы до ясности требований</li><li><strong>Черновик плана</strong>: Генерация структурированного плана в Markdown</li><li><strong>Параллельное делегирование</strong>: <ul><li><code>delegate_task(agent=&quot;oracle&quot;, prompt=&quot;проверить архитектурные решения&quot;)</code> → [фоновый режим]</li><li><code>delegate_task(agent=&quot;metis&quot;, prompt=&quot;выявить потенциальные риски&quot;)</code> → [фоновый режим]</li><li><code>delegate_task(agent=&quot;momus&quot;, prompt=&quot;проверить полноту плана&quot;)</code> → [фоновый режим]</li></ul></li><li><strong>Интеграция обратной связи</strong>: Улучшение плана</li><li><strong>Вывод плана</strong>: Сохранение в <code>.sisyphus/plans/{name}.md</code></li></ol><p><strong>Ограничения</strong>: Только планирование, без реализации кода (принудительно через <code>prometheus-md-only</code> Hook)</p><hr><h4 id="sisyphus-junior-исполнитель-задач" tabindex="-1">Sisyphus Junior - Исполнитель задач <a class="header-anchor" href="#sisyphus-junior-исполнитель-задач" aria-label="Permalink to &quot;Sisyphus Junior - Исполнитель задач&quot;">​</a></h4><p><strong>Роль</strong>: Исполнитель подагентов, генерируемых по категориям</p><p><strong>Возможности</strong>:</p><ul><li>Наследование конфигурации Category (модель, temperature, prompt_append)</li><li>Загрузка Skills (профессиональные навыки)</li><li>Выполнение делегированных подзадач</li></ul><p><strong>Рекомендуемая модель</strong>: Наследуется от Category (по умолчанию <code>anthropic/claude-sonnet-4-5</code>)</p><p><strong>Сценарии использования</strong>:</p><ul><li>Автоматическая генерация при использовании <code>delegate_task(category=&quot;...&quot;, skills=[&quot;...&quot;])</code></li><li>Задачи, требующие специфической комбинации Category и Skill</li><li>Легковесные быстрые задачи (Category &quot;quick&quot; использует модель Haiku)</li></ul><p><strong>Способ вызова</strong>: Автоматическая генерация через инструмент <code>delegate_task</code></p><p><strong>Ограничения</strong>: Запрещены task, delegate_task (нельзя делегировать повторно)</p><hr><h2 id="быстрая-справка-по-вызову-агентов" tabindex="-1">Быстрая справка по вызову агентов <a class="header-anchor" href="#быстрая-справка-по-вызову-агентов" aria-label="Permalink to &quot;Быстрая справка по вызову агентов&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Агент</th><th>Способ вызова</th><th>Условия активации</th></tr></thead><tbody><tr><td><strong>Sisyphus</strong></td><td>Агент по умолчанию</td><td>Повседневные задачи разработки</td></tr><tr><td><strong>Atlas</strong></td><td>Команда <code>/start-work</code></td><td>Запуск выполнения проекта</td></tr><tr><td><strong>Oracle</strong></td><td><code>@oracle</code> или <code>delegate_task(agent=&quot;oracle&quot;)</code></td><td>Сложные архитектурные решения, 2+ неудачных исправления</td></tr><tr><td><strong>Librarian</strong></td><td><code>@librarian</code> или <code>delegate_task(agent=&quot;librarian&quot;)</code></td><td>Автоматическая активация при упоминании внешних библиотек/источников</td></tr><tr><td><strong>Explore</strong></td><td><code>@explore</code> или <code>delegate_task(agent=&quot;explore&quot;)</code></td><td>Автоматическая активация при вовлечении 2+ модулей</td></tr><tr><td><strong>Multimodal Looker</strong></td><td>Инструмент <code>look_at</code></td><td>Необходимость анализа PDF/изображений</td></tr><tr><td><strong>Prometheus</strong></td><td><code>@prometheus</code> или <code>/start-work</code></td><td>Промпт содержит &quot;Prometheus&quot; или требуется планирование</td></tr><tr><td><strong>Metis</strong></td><td>Автоматический вызов Prometheus</td><td>Автоматический анализ перед планированием</td></tr><tr><td><strong>Momus</strong></td><td>Автоматический вызов Prometheus</td><td>Автоматическая проверка после генерации плана</td></tr><tr><td><strong>Sisyphus Junior</strong></td><td><code>delegate_task(category=...)</code></td><td>Автоматическая генерация при использовании Category/Skill</td></tr></tbody></table><hr><h2 id="когда-использовать-какого-агента" tabindex="-1">Когда использовать какого агента <a class="header-anchor" href="#когда-использовать-какого-агента" aria-label="Permalink to &quot;Когда использовать какого агента&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Быстрое дерево решений</p><p><strong>Сценарий 1: Повседневная разработка (написание кода, исправление багов)</strong> → <strong>Sisyphus</strong> (по умолчанию)</p><p><strong>Сценарий 2: Сложные архитектурные решения</strong> → Консультация <strong>@oracle</strong></p><p><strong>Сценарий 3: Необходимость поиска документации или реализации внешней библиотеки</strong> → <strong>@librarian</strong> или автоматическая активация</p><p><strong>Сценарий 4: Незнакомая кодовая база, необходимость найти связанный код</strong> → <strong>@explore</strong> или автоматическая активация (2+ модуля)</p><p><strong>Сценарий 5: Сложный проект требует детального плана</strong> → <strong>@prometheus</strong> или использование <code>/start-work</code></p><p><strong>Сценарий 6: Необходимость анализа PDF или изображений</strong> → Инструмент <strong>look_at</strong> (автоматическая активация Multimodal Looker)</p><p><strong>Сценарий 7: Быстрая простая задача, экономия средств</strong> → <code>delegate_task(category=&quot;quick&quot;)</code></p><p><strong>Сценарий 8: Необходимость профессиональных операций Git</strong> → <code>delegate_task(category=&quot;quick&quot;, skills=[&quot;git-master&quot;])</code></p><p><strong>Сценарий 9: Необходимость проектирования Frontend UI</strong> → <code>delegate_task(category=&quot;visual-engineering&quot;)</code></p><p><strong>Сценарий 10: Необходимость задач с высоким интеллектуальным рассуждением</strong> → <code>delegate_task(category=&quot;ultrabrain&quot;)</code></p></div><hr><h2 id="примеры-взаимодеиствия-агентов-полныи-рабочии-процесс" tabindex="-1">Примеры взаимодействия агентов: Полный рабочий процесс <a class="header-anchor" href="#примеры-взаимодеиствия-агентов-полныи-рабочии-процесс" aria-label="Permalink to &quot;Примеры взаимодействия агентов: Полный рабочий процесс&quot;">​</a></h2><h3 id="пример-1-разработка-сложнои-функции" tabindex="-1">Пример 1: Разработка сложной функции <a class="header-anchor" href="#пример-1-разработка-сложнои-функции" aria-label="Permalink to &quot;Пример 1: Разработка сложной функции&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Пользователь: Разработать систему аутентификации пользователей</span></span>
<span class="line"><span></span></span>
<span class="line"><span>→ Sisyphus получает задачу</span></span>
<span class="line"><span>  → Анализирует требования, обнаруживает необходимость внешней библиотеки (JWT)</span></span>
<span class="line"><span>  → Параллельное делегирование:</span></span>
<span class="line"><span>    - @librarian: &quot;Найти лучшие практики JWT для Next.js&quot; → [фоновый режим]</span></span>
<span class="line"><span>    - @explore: &quot;Найти существующий код, связанный с аутентификацией&quot; → [фоновый режим]</span></span>
<span class="line"><span>  → Ожидает результаты, интегрирует информацию</span></span>
<span class="line"><span>  → Реализует функцию аутентификации JWT</span></span>
<span class="line"><span>  → После завершения делегирует:</span></span>
<span class="line"><span>    - @oracle: &quot;Проверить архитектурный дизайн&quot; → [фоновый режим]</span></span>
<span class="line"><span>  → Оптимизирует на основе рекомендаций</span></span></code></pre></div><hr><h3 id="пример-2-планирование-проекта" tabindex="-1">Пример 2: Планирование проекта <a class="header-anchor" href="#пример-2-планирование-проекта" aria-label="Permalink to &quot;Пример 2: Планирование проекта&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Пользователь: Использовать Prometheus для планирования этого проекта</span></span>
<span class="line"><span></span></span>
<span class="line"><span>→ Prometheus получает задачу</span></span>
<span class="line"><span>  → Режим интервью:</span></span>
<span class="line"><span>    - Вопрос 1: Каковы основные функции?</span></span>
<span class="line"><span>    - [Ответ пользователя]</span></span>
<span class="line"><span>    - Вопрос 2: Целевая аудитория?</span></span>
<span class="line"><span>    - [Ответ пользователя]</span></span>
<span class="line"><span>    - ...</span></span>
<span class="line"><span>  → После уточнения требований, параллельное делегирование:</span></span>
<span class="line"><span>    - delegate_task(agent=&quot;oracle&quot;, prompt=&quot;проверить архитектурные решения&quot;) → [фоновый режим]</span></span>
<span class="line"><span>    - delegate_task(agent=&quot;metis&quot;, prompt=&quot;выявить потенциальные риски&quot;) → [фоновый режим]</span></span>
<span class="line"><span>    - delegate_task(agent=&quot;momus&quot;, prompt=&quot;проверить полноту плана&quot;) → [фоновый режим]</span></span>
<span class="line"><span>  → Ожидает завершения всех фоновых задач</span></span>
<span class="line"><span>  → Интегрирует обратную связь, улучшает план</span></span>
<span class="line"><span>  → Выводит документ плана в Markdown</span></span>
<span class="line"><span>→ Пользователь просматривает план, подтверждает</span></span>
<span class="line"><span>→ Использует /start-work для запуска выполнения</span></span></code></pre></div><hr><h2 id="права-доступа-и-ограничения-агентов" tabindex="-1">Права доступа и ограничения агентов <a class="header-anchor" href="#права-доступа-и-ограничения-агентов" aria-label="Permalink to &quot;Права доступа и ограничения агентов&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Агент</th><th>write</th><th>edit</th><th>bash</th><th>delegate_task</th><th>webfetch</th><th>read</th><th>LSP</th><th>AST-Grep</th></tr></thead><tbody><tr><td><strong>Sisyphus</strong></td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Atlas</strong></td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Oracle</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Librarian</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Explore</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Multimodal Looker</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Prometheus</strong></td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Metis</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Momus</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Sisyphus Junior</strong></td><td>✅</td><td>✅</td><td>✅</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table><hr><h2 id="краткое-содержание-урока" tabindex="-1">Краткое содержание урока <a class="header-anchor" href="#краткое-содержание-урока" aria-label="Permalink to &quot;Краткое содержание урока&quot;">​</a></h2><p>10 AI-агентов oh-my-opencode охватывают все этапы процесса разработки:</p><ul><li><strong>Оркестрация и выполнение</strong>: Sisyphus (главный оркестратор), Atlas (управление TODO)</li><li><strong>Консультанты и проверка</strong>: Oracle (стратегический консультант), Metis (предварительный анализ планирования), Momus (проверка плана)</li><li><strong>Исследование и изучение</strong>: Librarian (исследование множественных репозиториев), Explore (изучение кодовой базы), Multimodal Looker (анализ медиа)</li><li><strong>Планирование</strong>: Prometheus (стратегическое планирование), Sisyphus Junior (выполнение подзадач)</li></ul><p><strong>Ключевые моменты</strong>:</p><ol><li>Не рассматривайте AI как универсального помощника, рассматривайте как профессиональную команду</li><li>Выбирайте наиболее подходящего агента по типу задачи</li><li>Используйте параллельное делегирование для повышения эффективности (Librarian, Explore, Oracle могут работать в фоновом режиме)</li><li>Понимайте ограничения прав доступа каждого агента (агенты только для чтения не могут изменять код)</li><li>Взаимодействие между агентами может формировать полный рабочий процесс (планирование → выполнение → проверка)</li></ol><hr><h2 id="анонс-следующего-урока" tabindex="-1">Анонс следующего урока <a class="header-anchor" href="#анонс-следующего-урока" aria-label="Permalink to &quot;Анонс следующего урока&quot;">​</a></h2><blockquote><p>В следующем уроке мы изучим <strong><a href="./../prometheus-planning/">Планирование Prometheus: Сбор требований в формате интервью</a></strong>.</p><p>Вы узнаете:</p><ul><li>Как использовать Prometheus для сбора требований в формате интервью</li><li>Как генерировать структурированный рабочий план</li><li>Как заставить Metis и Momus проверить план</li><li>Как получать и отменять фоновые задачи</li></ul></blockquote><hr><h2 id="приложение-справочник-по-исходному-коду" tabindex="-1">Приложение: Справочник по исходному коду <a class="header-anchor" href="#приложение-справочник-по-исходному-коду" aria-label="Permalink to &quot;Приложение: Справочник по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы развернуть расположение исходного кода</strong></summary><blockquote><p>Дата обновления: 2026-01-26</p></blockquote><table tabindex="0"><thead><tr><th>Агент</th><th>Путь к файлу</th><th>Номера строк</th></tr></thead><tbody><tr><td>Главный оркестратор Sisyphus</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/sisyphus.ts" target="_blank" rel="noreferrer"><code>src/agents/sisyphus.ts</code></a></td><td>-</td></tr><tr><td>Главный оркестратор Atlas</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/atlas.ts" target="_blank" rel="noreferrer"><code>src/agents/atlas.ts</code></a></td><td>-</td></tr><tr><td>Консультант Oracle</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/oracle.ts" target="_blank" rel="noreferrer"><code>src/agents/oracle.ts</code></a></td><td>1-123</td></tr><tr><td>Исследовательский эксперт Librarian</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/librarian.ts" target="_blank" rel="noreferrer"><code>src/agents/librarian.ts</code></a></td><td>1-327</td></tr><tr><td>Поисковый эксперт Explore</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/explore.ts" target="_blank" rel="noreferrer"><code>src/agents/explore.ts</code></a></td><td>1-123</td></tr><tr><td>Multimodal Looker</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/multimodal-looker.ts" target="_blank" rel="noreferrer"><code>src/agents/multimodal-looker.ts</code></a></td><td>1-57</td></tr><tr><td>Планировщик Prometheus</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/prometheus-prompt.ts" target="_blank" rel="noreferrer"><code>src/agents/prometheus-prompt.ts</code></a></td><td>1-1196</td></tr><tr><td>Предварительный анализ Metis</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/metis.ts" target="_blank" rel="noreferrer"><code>src/agents/metis.ts</code></a></td><td>1-316</td></tr><tr><td>Проверяющий планов Momus</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/momus.ts" target="_blank" rel="noreferrer"><code>src/agents/momus.ts</code></a></td><td>1-445</td></tr><tr><td>Sisyphus Junior</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/sisyphus-junior.ts" target="_blank" rel="noreferrer"><code>src/agents/sisyphus-junior.ts</code></a></td><td>-</td></tr><tr><td>Определение метаданных агентов</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/types.ts" target="_blank" rel="noreferrer"><code>src/agents/types.ts</code></a></td><td>-</td></tr><tr><td>Ограничения инструментов агентов</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/shared/permission-compat.ts" target="_blank" rel="noreferrer"><code>src/shared/permission-compat.ts</code></a></td><td>-</td></tr></tbody></table><p><strong>Ключевые конфигурации</strong>:</p><ul><li><code>ORACLE_PROMPT_METADATA</code>: Метаданные агента Oracle (условия активации, сценарии использования)</li><li><code>LIBRARIAN_PROMPT_METADATA</code>: Метаданные агента Librarian</li><li><code>EXPLORE_PROMPT_METADATA</code>: Метаданные агента Explore</li><li><code>MULTIMODAL_LOOKER_PROMPT_METADATA</code>: Метаданные агента Multimodal Looker</li><li><code>METIS_SYSTEM_PROMPT</code>: Системный промпт агента Metis</li><li><code>MOMUS_SYSTEM_PROMPT</code>: Системный промпт агента Momus</li></ul><p><strong>Ключевые функции</strong>:</p><ul><li><code>createOracleAgent(model)</code>: Создание конфигурации агента Oracle</li><li><code>createLibrarianAgent(model)</code>: Создание конфигурации агента Librarian</li><li><code>createExploreAgent(model)</code>: Создание конфигурации агента Explore</li><li><code>createMultimodalLookerAgent(model)</code>: Создание конфигурации агента Multimodal Looker</li><li><code>createMetisAgent(model)</code>: Создание конфигурации агента Metis</li><li><code>createMomusAgent(model)</code>: Создание конфигурации агента Momus</li></ul><p><strong>Ограничения прав доступа</strong>:</p><ul><li><code>createAgentToolRestrictions()</code>: Создание ограничений инструментов агентов (используется Oracle, Librarian, Explore, Metis, Momus)</li><li><code>createAgentToolAllowlist()</code>: Создание белого списка инструментов агентов (используется Multimodal Looker)</li></ul></details>`,160)])])}const h=o(n,[["render",r]]);export{u as __pageData,h as default};
